  it('h004 timestamp defined', async () => { const r=await request(app).get('/health'); expect(r.body.timestamp).toBeDefined(); });
  it('h005 timestamp valid ISO', async () => { const r=await request(app).get('/health'); expect(new Date(r.body.timestamp).getTime()).not.toBeNaN(); });
