  it('h007 body has 3 keys', async () => { const r=await request(app).get('/health'); expect(Object.keys(r.body).sort()).toEqual(['service','status','timestamp']); });
  it('h008 no auth required', async () => { const r=await request(app).get('/health'); expect(r.status).not.toBe(401); });
  it('h009 status is string', async () => { const r=await request(app).get('/health'); expect(typeof r.body.status).toBe('string'); });
  it('h010 service is string', async () => { const r=await request(app).get('/health'); expect(typeof r.body.service).toBe('string'); });
  it('h011 timestamp is string', async () => { const r=await request(app).get('/health'); expect(typeof r.body.timestamp).toBe('string'); });
  it('h012 status not error', async () => { const r=await request(app).get('/health'); expect(r.body.status).not.toBe('error'); });
  it('h013 service no spaces', async () => { const r=await request(app).get('/health'); expect(r.body.service).not.toContain(' '); });
  it('h014 timestamp ends Z', async () => { const r=await request(app).get('/health'); expect(r.body.timestamp).toMatch(/Z$/); });
  it('h015 no success field', async () => { const r=await request(app).get('/health'); expect(r.body.success).toBeUndefined(); });
  it('h016 no error field', async () => { const r=await request(app).get('/health'); expect(r.body.error).toBeUndefined(); });
