  it('h043 Accept header json', async () => { const r=await request(app).get('/health').set('Accept','application/json'); expect(r.headers['content-type']).toMatch(/json/); });
  it('h044 timestamp is recent', async () => { const before=Date.now();const r=await request(app).get('/health');const after=Date.now();const ts=new Date(r.body.timestamp).getTime();expect(ts).toBeGreaterThanOrEqual(before-1000);expect(ts).toBeLessThanOrEqual(after+1000); });
  it('h045 multi params 200', async () => { const r=await request(app).get('/health?x=1&y=2'); expect(r.status).toBe(200); });
  it('h046 status length 2', async () => { const r=await request(app).get('/health'); expect(r.body.status.length).toBe(2); });
  it('h047 service length 10', async () => { const r=await request(app).get('/health'); expect(r.body.service.length).toBe(10); });
  it('h048 service starts api-', async () => { const r=await request(app).get('/health'); expect(r.body.service.startsWith('api-')).toBe(true); });
  it('h049 no code field', async () => { const r=await request(app).get('/health'); expect(r.body.code).toBeUndefined(); });
  it('h050 timestamp has colon', async () => { const r=await request(app).get('/health'); expect(r.body.timestamp).toContain(':'); });
