describe('GET /api/search - missing or empty q', () => {
  beforeEach(() => clearStore());
  it('sq001 no q returns 400', async () => { const r=await request(app).get('/api/search'); expect(r.status).toBe(400); });
  it('sq002 empty q returns 400', async () => { const r=await request(app).get('/api/search?q='); expect(r.status).toBe(400); });
  it('sq003 whitespace q returns 400', async () => { const r=await request(app).get('/api/search?q=%20%20'); expect(r.status).toBe(400); });
  it('sq004 missing q success false', async () => { const r=await request(app).get('/api/search'); expect(r.body.success).toBe(false); });
  it('sq005 missing q MISSING_QUERY', async () => { const r=await request(app).get('/api/search'); expect(r.body.code).toBe('MISSING_QUERY'); });
  it('sq006 missing q error string', async () => { const r=await request(app).get('/api/search'); expect(typeof r.body.error).toBe('string'); });
  it('sq007 empty q MISSING_QUERY', async () => { const r=await request(app).get('/api/search?q='); expect(r.body.code).toBe('MISSING_QUERY'); });
  it('sq008 whitespace q success false', async () => { const r=await request(app).get('/api/search?q=%20'); expect(r.body.success).toBe(false); });
  it('sq009 missing q no data', async () => { const r=await request(app).get('/api/search'); expect(r.body.data).toBeUndefined(); });
  it('sq010 empty q no data', async () => { const r=await request(app).get('/api/search?q='); expect(r.body.data).toBeUndefined(); });
});

