describe('GET /api/search - limit and offset', () => {
  beforeEach(() => clearStore());
  it('lo001 limit=5 at most 5', async () => { const r=await request(app).get('/api/search?q=a&limit=5'); expect(r.body.data.items.length).toBeLessThanOrEqual(5); });
  it('lo002 limit=1 at most 1', async () => { const r=await request(app).get('/api/search?q=a&limit=1'); expect(r.body.data.items.length).toBeLessThanOrEqual(1); });
  it('lo003 limit=100 accepted', async () => { const r=await request(app).get('/api/search?q=a&limit=100'); expect(r.body.data.limit).toBe(100); });
  it('lo004 limit=200 clamped to 100', async () => { const r=await request(app).get('/api/search?q=a&limit=200'); expect(r.body.data.limit).toBe(100); });
  it('lo005 limit=0 defaults to 20', async () => { const r=await request(app).get('/api/search?q=a&limit=0'); expect(r.body.data.limit).toBe(20); });
  it('lo006 limit=-1 defaults to 20', async () => { const r=await request(app).get('/api/search?q=a&limit=-1'); expect(r.body.data.limit).toBe(20); });
  it('lo007 limit=abc defaults to 20', async () => { const r=await request(app).get('/api/search?q=a&limit=abc'); expect(r.body.data.limit).toBe(20); });
  it('lo008 offset=0 default', async () => { const r=await request(app).get('/api/search?q=a&offset=0'); expect(r.body.data.offset).toBe(0); });
  it('lo009 offset=5 respected', async () => { const r=await request(app).get('/api/search?q=a&offset=5'); expect(r.body.data.offset).toBe(5); });
  it('lo010 offset=-1 defaults 0', async () => { const r=await request(app).get('/api/search?q=a&offset=-1'); expect(r.body.data.offset).toBe(0); });
  it('lo011 offset=abc defaults 0', async () => { const r=await request(app).get('/api/search?q=a&offset=abc'); expect(r.body.data.offset).toBe(0); });
  it('lo012 offset>total empty items', async () => { const r=await request(app).get('/api/search?q=ncr&offset=9999'); expect(r.body.data.items.length).toBe(0); });
  it('lo013 limit in response matches', async () => { const r=await request(app).get('/api/search?q=a&limit=10'); expect(r.body.data.limit).toBe(10); });
  it('lo014 offset in response matches', async () => { const r=await request(app).get('/api/search?q=ncr&offset=2'); expect(r.body.data.offset).toBe(2); });
  it('lo015 page1 page2 non-overlapping', async () => { const p1=await request(app).get('/api/search?q=a&limit=5&offset=0'); const p2=await request(app).get('/api/search?q=a&limit=5&offset=5'); const ids1=p1.body.data.items.map((i:any)=>i.id); const ids2=p2.body.data.items.map((i:any)=>i.id); const overlap=ids1.filter((id:string)=>ids2.includes(id)); expect(overlap.length).toBe(0); });
  it('lo016 limit=50 accepted', async () => { const r=await request(app).get('/api/search?q=a&limit=50'); expect(r.body.data.limit).toBe(50); });
  it('lo017 total consistent pages', async () => { const p1=await request(app).get('/api/search?q=a&limit=5&offset=0'); const p2=await request(app).get('/api/search?q=a&limit=5&offset=5'); expect(p1.body.data.total).toBe(p2.body.data.total); });
  it('lo018 page total = full total', async () => { const full=await request(app).get('/api/search?q=a&limit=100'); const page=await request(app).get('/api/search?q=a&limit=5&offset=0'); expect(page.body.data.total).toBe(full.body.data.total); });
  it('lo019 page1 not in page3', async () => { const p1=await request(app).get('/api/search?q=a&limit=3&offset=0'); const p3=await request(app).get('/api/search?q=a&limit=3&offset=6'); const ids1=p1.body.data.items.map((i:any)=>i.id); const ids3=p3.body.data.items.map((i:any)=>i.id); ids1.forEach((id:string)=>expect(ids3).not.toContain(id)); });
  it('lo020 limit and offset combined', async () => { const r=await request(app).get('/api/search?q=a&limit=3&offset=1'); expect(r.body.data.limit).toBe(3); expect(r.body.data.offset).toBe(1); });
});

describe('GET /api/search - sort', () => {
  beforeEach(() => clearStore());
  it('so001 sort=relevance 200', async () => { const r=await request(app).get('/api/search?q=ncr&sort=relevance'); expect(r.status).toBe(200); });
  it('so002 sort=date 200', async () => { const r=await request(app).get('/api/search?q=ncr&sort=date'); expect(r.status).toBe(200); });
  it('so003 sort=title 200', async () => { const r=await request(app).get('/api/search?q=ncr&sort=title'); expect(r.status).toBe(200); });
  it('so004 invalid sort 200', async () => { const r=await request(app).get('/api/search?q=ncr&sort=badvalue'); expect(r.status).toBe(200); });
  it('so005 sort=date newest first', async () => { const r=await request(app).get('/api/search?q=ncr&sort=date&limit=10'); const items=r.body.data.items; for(let i=1;i<items.length;i++){const prev=new Date(items[i-1].createdAt).getTime();const curr=new Date(items[i].createdAt).getTime();expect(prev).toBeGreaterThanOrEqual(curr);} });
  it('so006 sort=title alphabetical', async () => { const r=await request(app).get('/api/search?q=a&sort=title&limit=50'); const items=r.body.data.items; for(let i=1;i<items.length;i++){expect(items[i-1].title.localeCompare(items[i].title)).toBeLessThanOrEqual(0);} });
  it('so007 sort=relevance top highest score', async () => { const r=await request(app).get('/api/search?q=ncr&sort=relevance&type=ncr&limit=10'); const items=r.body.data.items; if(items.length>1){expect((items[0].score??0)).toBeGreaterThanOrEqual((items[items.length-1].score??0));} });
  it('so008 sort=DATE uppercase 200', async () => { const r=await request(app).get('/api/search?q=ncr&sort=DATE'); expect(r.status).toBe(200); });
  it('so009 all sorts 200', async () => { for(const s of ['relevance','date','title']){const r=await request(app).get('/api/search?q=a&sort='+s); expect(r.status).toBe(200);} });
  it('so010 sort=relevance success', async () => { const r=await request(app).get('/api/search?q=ncr&sort=relevance'); expect(r.body.success).toBe(true); });
  it('so011 sort=date success', async () => { const r=await request(app).get('/api/search?q=ncr&sort=date'); expect(r.body.success).toBe(true); });
  it('so012 sort=title success', async () => { const r=await request(app).get('/api/search?q=ncr&sort=title'); expect(r.body.success).toBe(true); });
  it('so013 all params + relevance', async () => { const r=await request(app).get('/api/search?q=ncr&type=ncr&limit=5&offset=0&sort=relevance'); expect(r.status).toBe(200); expect(r.body.data.type).toBe('ncr'); expect(r.body.data.limit).toBe(5); });
  it('so014 all params + date', async () => { const r=await request(app).get('/api/search?q=a&type=all&limit=10&offset=0&sort=date'); expect(r.status).toBe(200); });
  it('so015 all params + title', async () => { const r=await request(app).get('/api/search?q=a&type=all&limit=10&offset=0&sort=title'); expect(r.status).toBe(200); });
});

