  it('method_DELETE_api_search_suggest returns 404', async () => { const r=await request(app).delete('/api/search/suggest'); expect(r.status).toBe(404); });
  it('method_PATCH_api_search_recent returns 404', async () => { const r=await request(app).patch('/api/search/recent'); expect(r.status).toBe(404); });
  it('method_POST_health returns 404', async () => { const r=await request(app).post('/health'); expect(r.status).toBe(404); });
