describe('Response body structural validation', () => {
  beforeEach(() => clearStore());
  it('struct001 search items not null', async () => { const r=await request(app).get('/api/search?q=ncr'); expect(r.body.data.items).not.toBeNull(); });
  it('struct002 search total not null', async () => { const r=await request(app).get('/api/search?q=ncr'); expect(r.body.data.total).not.toBeNull(); });
  it('struct003 search query not null', async () => { const r=await request(app).get('/api/search?q=ncr'); expect(r.body.data.query).not.toBeNull(); });
  it('struct004 search type not null', async () => { const r=await request(app).get('/api/search?q=ncr'); expect(r.body.data.type).not.toBeNull(); });
  it('struct005 search data is obj', async () => { const r=await request(app).get('/api/search?q=ncr'); expect(typeof r.body.data).toBe('object'); });
  it('struct006 suggest data is obj', async () => { const r=await request(app).get('/api/search/suggest?q=nc'); expect(typeof r.body.data).toBe('object'); });
  it('struct007 recent data is obj', async () => { const r=await request(app).get('/api/search/recent'); expect(typeof r.body.data).toBe('object'); });
  it('struct008 delete data is obj', async () => { const r=await request(app).delete('/api/search/recent'); expect(typeof r.body.data).toBe('object'); });
  it('struct009 search success not null', async () => { const r=await request(app).get('/api/search?q=ncr'); expect(r.body.success).not.toBeNull(); });
  it('struct010 suggest success not null', async () => { const r=await request(app).get('/api/search/suggest?q=nc'); expect(r.body.success).not.toBeNull(); });
  it('struct011 data.query is string', async () => { const r=await request(app).get('/api/search?q=ncr'); expect(typeof r.body.data.query).toBe('string'); });
  it('struct012 data.type is string', async () => { const r=await request(app).get('/api/search?q=ncr'); expect(typeof r.body.data.type).toBe('string'); });
  it('struct013 data.items not undefined', async () => { const r=await request(app).get('/api/search?q=ncr'); expect(r.body.data.items).not.toBeUndefined(); });
  it('struct014 data.total not undefined', async () => { const r=await request(app).get('/api/search?q=ncr'); expect(r.body.data.total).not.toBeUndefined(); });
  it('struct015 data.limit not undefined', async () => { const r=await request(app).get('/api/search?q=ncr'); expect(r.body.data.limit).not.toBeUndefined(); });
  it('struct016 data.offset not undefined', async () => { const r=await request(app).get('/api/search?q=ncr'); expect(r.body.data.offset).not.toBeUndefined(); });
  it('struct017 data.query not undefined', async () => { const r=await request(app).get('/api/search?q=ncr'); expect(r.body.data.query).not.toBeUndefined(); });
  it('struct018 data.type not undefined', async () => { const r=await request(app).get('/api/search?q=ncr'); expect(r.body.data.type).not.toBeUndefined(); });
  it('struct019 suggestions not undefined', async () => { const r=await request(app).get('/api/search/suggest?q=nc'); expect(r.body.data.suggestions).not.toBeUndefined(); });
  it('struct020 searches not undefined', async () => { const r=await request(app).get('/api/search/recent'); expect(r.body.data.searches).not.toBeUndefined(); });
  it('struct021 delete message not undefined', async () => { const r=await request(app).delete('/api/search/recent'); expect(r.body.data.message).not.toBeUndefined(); });
  it('struct022 delete message not null', async () => { const r=await request(app).delete('/api/search/recent'); expect(r.body.data.message).not.toBeNull(); });
  it('struct023 items total nonneg', async () => { const r=await request(app).get('/api/search?q=ncr'); expect(r.body.data.total).toBeGreaterThanOrEqual(0); });
  it('struct024 items length nonneg', async () => { const r=await request(app).get('/api/search?q=ncr'); expect(r.body.data.items.length).toBeGreaterThanOrEqual(0); });
  it('struct025 suggest length nonneg', async () => { const r=await request(app).get('/api/search/suggest?q=nc'); expect(r.body.data.suggestions.length).toBeGreaterThanOrEqual(0); });
  it('struct026 recent length nonneg', async () => { const r=await request(app).get('/api/search/recent'); expect(r.body.data.searches.length).toBeGreaterThanOrEqual(0); });
  it('struct027 400 error not null', async () => { const r=await request(app).get('/api/search'); expect(r.body.error).not.toBeNull(); });
  it('struct028 400 code not null', async () => { const r=await request(app).get('/api/search'); expect(r.body.code).not.toBeNull(); });
  it('struct029 400 success not null', async () => { const r=await request(app).get('/api/search'); expect(r.body.success).not.toBeNull(); });
  it('struct030 health body not undefined', async () => { const r=await request(app).get('/health'); expect(r.body).not.toBeUndefined(); });
});
